import { createStore } from 'vuex'
import { authService } from '@/services/authService'
import { STORAGE_KEYS, clearAuthStorage } from '@/utils/storage'
import profile from '@/api/profile'

export default createStore({
  state: {
    isAuthenticated: false,
    userInfo: null,
    basicInfo: null,
    completeness: null
  },

  mutations: {
    SET_AUTH(state, isAuthenticated) {
      state.isAuthenticated = isAuthenticated
    },

    SET_USER_INFO(state, userInfo) {
      state.userInfo = {
        ...state.userInfo,
        ...userInfo
      }
    },

    SET_BASIC_INFO(state, basicInfo) {
      state.basicInfo = {
        ...state.basicInfo,
        ...basicInfo
      }
    },

    SET_COMPLETENESS(state, completeness) {
      state.completeness = completeness
    },

    SET_AVATAR_UPDATE_TIME(state, timestamp) {
      state.avatarUpdateTime = timestamp
    }
  },

  getters: {
    userAvatar: state => {
      return state.basicInfo?.avatar || '/default-avatar.png'
    },

    userName: state => {
      return state.basicInfo?.name || state.userInfo?.username || '未设置昵称'
    },

    userPhone: state => {
      return state.basicInfo?.phone || state.userInfo?.phone
    },

    profileCompleteness: state => {
      return state.completeness || 0
    }
  },

  actions: {
    async checkAuth({ commit, dispatch }) {
      const isAuthenticated = authService.isAuthenticated()
      commit('SET_AUTH', isAuthenticated)
      if (isAuthenticated) {
        await dispatch('fetchUserInfo')
      }
      return isAuthenticated
    },

    async fetchUserInfo({ commit }) {
      try {
        const response = await profile.getBasicInfo()
        console.log('API Response:', response.data)

        if (response.data?.code === 200) {
          const { user, basic_info } = response.data.data
          console.log('Extracted Data:', { user, basic_info })

          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
          return response.data.data
        }
      } catch (error) {
        console.error('Failed to get user info:', error)
        if (error.response?.status === 401) {
          commit('SET_AUTH', false)
          commit('SET_USER_INFO', null)
          commit('SET_BASIC_INFO', null)
        }
        throw error
      }
    },

    async updateBasicInfo({ commit }, { type, data }) {
      try {
        let response
        if (type === 'avatar') {
          response = await profile.uploadAvatar(data)
        } else if (type === 'basic') {
          response = await profile.updateBasicInfo(data)
        } else {
          throw new Error('未知的更新类型')
        }

        if (response?.data?.code === 200) {
          if (type === 'avatar') {
            commit('SET_AVATAR_UPDATE_TIME', Date.now())
          }
          const { user, basic_info } = response.data.data
          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
          return response
        }
        throw new Error(response?.data?.message || '更新失败')
      } catch (error) {
        console.error('Failed to update basic info:', error)
        throw error
      }
    },

    async logout({ commit }) {
      try {
        await authService.logout()
      } catch (error) {
        console.error('Logout failed:', error)
      } finally {
        clearAuthStorage()
        commit('SET_AUTH', false)
        commit('SET_USER_INFO', null)
        commit('SET_BASIC_INFO', null)
      }
    },

    async fetchCompleteness({ commit }) {
      try {
        const response = await profile.getCompleteness()
        if (response.data?.code === 200) {
          commit('SET_COMPLETENESS', response.data.data)
        }
      } catch (error) {
        console.error('Failed to get completeness:', error)
      }
    },

    async login({ commit }, { tokens, user }) {
      try {
        // 保存 tokens
        localStorage.setItem(STORAGE_KEYS.TOKEN, tokens.access)
        localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokens.refresh)

        // 保存用户信息
        localStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(user))

        // 更新 store 状态
        commit('SET_TOKEN', tokens.access)
        commit('SET_REFRESH_TOKEN', tokens.refresh)
        commit('SET_USER', user)
        commit('SET_LOGGED_IN', true)

        // 获取用户信息
        await this.dispatch('fetchUserInfo')

        return true
      } catch (error) {
        console.error('Login error:', error)
        throw error
      }
    }
  }
})
